sql:
SELECT COUNT(*) AS active_contents_count
   FROM humor_contents
   WHERE is_active = 1;

SELECT content_id, popularity_score
FROM humor_contents
ORDER BY popularity_score DESC;

SELECT content_type, COUNT(content_id) AS content_count
FROM humor_contents
GROUP BY content_type;

SELECT hc.content_id
FROM humor_contents hc
WHERE hc.popularity_score > (
    SELECT AVG(popularity_score)
    FROM humor_contents
);

SELECT content_text 
FROM humor_contents 
WHERE is_active = 1;

external_knowledge:
Active content refers to content with the 'is_active' flag set to 1; 
The 'content_type' categorizes the humor content (e.g., one-liner, meme, video); 
Average popularity score is a measure of popularity, with higher values indicating greater popularity.

sql:
SELECT content_text
FROM humor_contents
WHERE popularity_score = (SELECT MAX(popularity_score) FROM humor_contents);

SELECT rating_type, COUNT(*) AS rating_count
FROM humor_ratings
GROUP BY rating_type;
